  1	import React, { useEffect, useState } from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { AboutModal as PfAboutModal, TextContent, TextList, TextListItem } from '@patternfly/react-core';
  4	import { detect } from 'detect-browser';
  5	import moment from 'moment/moment';
  6	import { helpers } from '../../helpers';
  7	import { useUserApi } from '../../hooks/useLoginApi';
  8	import { useStatusApi, type ApiStatusSuccessType } from '../../hooks/useStatusApi';
  9	import backgroundImageSrc from '../../images/aboutBg.png';
 10	
 11	interface AboutModalProps {
 12	  currentYear?: string;
 13	  isOpen?: boolean;
 14	  onClose?: () => void;
 15	  titleImg?: string;
 16	  uiName?: string;
 17	  uiVersion?: string;
 18	  useStatus?: typeof useStatusApi;
 19	  useUser?: typeof useUserApi;
 20	}
 21	
 22	const AboutModal: React.FC<AboutModalProps> = ({
 23	  currentYear = moment.utc(helpers.getCurrentDate()).format('YYYY'),
 24	  isOpen = false,
 25	  onClose = Function.prototype,
 26	  titleImg = helpers.getTitleImg(),
 27	  uiName = helpers.UI_NAME,
 28	  uiVersion = helpers.UI_VERSION,
 29	  useStatus = useStatusApi,
 30	  useUser = useUserApi
 31	}) => {
 32	  const { t } = useTranslation();
 33	  const { getStatus } = useStatus();
 34	  const { getUser } = useUser();
 35	  const [userName, setUserName] = useState<string>();
 36	  const [stats, setStats] = useState<ApiStatusSuccessType>();
 37	  const browser = detect();
 38	  const loadingClassName = (!stats && 'fadein') || '';
 39	
 40	  useEffect(() => {
 41	    if (isOpen && !stats) {
 42	      getUser().then(username => setUserName(username));
 43	      getStatus().then(
 44	        data => setStats(data),
 45	        error => console.error(`About status error: ${error} `)
 46	      );
 47	    }
 48	  }, [isOpen, getStatus, getUser, stats]);
 49	
 50	  return (
 51	    <PfAboutModal
 52	      aria-label={uiName}
 53	      backgroundImageSrc={backgroundImageSrc as string}
 54	      brandImageAlt={uiName}
 55	      brandImageSrc={titleImg}
 56	      isOpen={isOpen}
 57	      onClose={() => onClose()}
 58	      trademark={t('about.copyright', { year: currentYear })}
 59	    >
 60	      <TextContent className={loadingClassName}>
 61	        <TextList component="dl">
 62	          {userName && (
 63	            <React.Fragment>
 64	              <TextListItem component="dt">{t('about.username')}</TextListItem>
 65	              <TextListItem component="dd">{userName}</TextListItem>
 66	            </React.Fragment>
 67	          )}
 68	          {browser && (
 69	            <React.Fragment>
 70	              <TextListItem component="dt">{t('about.browser-version')}</TextListItem>
 71	              <TextListItem component="dd">{`${browser.name} ${browser.version}`}</TextListItem>
 72	            </React.Fragment>
 73	          )}
 74	          {browser && (
 75	            <React.Fragment>
 76	              <TextListItem component="dt">{t('about.browser-os')}</TextListItem>
 77	              <TextListItem component="dd">{browser.os || ''}</TextListItem>
 78	            </React.Fragment>
 79	          )}
 80	          {uiVersion && (
 81	            <React.Fragment>
 82	              <TextListItem component="dt">{t('about.ui-version')}</TextListItem>
 83	              <TextListItem component="dd">{uiVersion}</TextListItem>
 84	            </React.Fragment>
 85	          )}
 86	          {stats?.server_version && (
 87	            <React.Fragment>
 88	              <TextListItem className={loadingClassName} component="dt">
 89	                {t('about.server-version')}
 90	              </TextListItem>
 91	              <TextListItem className={loadingClassName} component="dd">
 92	                {stats.server_version}
 93	              </TextListItem>
 94	            </React.Fragment>
 95	          )}
 96	          {stats?.platform.machine && (
 97	            <React.Fragment>
 98	              <TextListItem className={loadingClassName} component="dt">
 99	                {t('about.server-cpu-arch')}
100	              </TextListItem>
101	              <TextListItem className={loadingClassName} component="dd">
102	                {stats.platform.machine}
103	              </TextListItem>
104	            </React.Fragment>
105	          )}
106	        </TextList>
107	      </TextContent>
108	    </PfAboutModal>
109	  );
110	};
111	
112	export { AboutModal as default, AboutModal, type AboutModalProps };

